// Input comes pre-parsed from TG-92 webhook router
const input = $input.first().json;
const from = (input.from || '').replace(/[^0-9+]/g, '');
const messageText = (input.messageText || '').trim();
const msgLower = messageText.toLowerCase();

// Check for keywords
const isOptOut = ['stop','unsubscribe','quit','cancel','end'].includes(msgLower);
const isOptIn = ['start','yes','subscribe'].includes(msgLower);
const isHelp = msgLower === 'help';
const isQuote = msgLower.includes('quote') || msgLower.includes('estimate') || msgLower.includes('price');
const isSchedule = msgLower.includes('schedule') || msgLower.includes('book') || msgLower.includes('appointment');
const isConfirm = msgLower === 'yes' || msgLower === 'confirm' || msgLower === 'y';
const isCancel = msgLower === 'no' || msgLower === 'cancel' || msgLower === 'n';

let intent = 'general';
if (isOptOut) intent = 'opt_out';
else if (isOptIn) intent = 'opt_in';
else if (isHelp) intent = 'help';
else if (isQuote) intent = 'quote_request';
else if (isSchedule) intent = 'schedule_request';
else if (isConfirm) intent = 'confirm';
else if (isCancel) intent = 'cancel';

return [{ json: { from, messageText, intent, received_at: new Date().toISOString() } }];

const customers = $input.all().map(i => i.json);
const customer = customers[0] || null;
const intent = $('Parse Inbound SMS').first().json.intent;
const name = customer?.first_name || 'there';

const replies = {
  opt_out: 'You have been unsubscribed from TotalGuard messages. Reply START to re-subscribe anytime.',
  opt_in: `Welcome back${customer ? ', ' + name : ''}! You\'re now subscribed to TotalGuard Yard Care updates. Reply STOP to unsubscribe.`,
  help: 'TotalGuard Yard Care Help:\n• QUOTE — get a free estimate\n• SCHEDULE — book a service\n• STOP — unsubscribe\n\nOr call (608) 535-6057',
  quote_request: `Hi ${name}! We\'d love to give you a free estimate. What service are you interested in? (Lawn mowing, spring cleanup, snow removal, gutter cleaning, hardscaping)`,
  schedule_request: `Hi ${name}! Ready to schedule? Call us at (608) 535-6057 or visit tgyardcare.com/get-quote and we\'ll get you on the calendar.`,
  confirm: `Got it, ${name}! Your appointment is confirmed. We\'ll send a reminder the day before. - TotalGuard`,
  cancel: `No problem, ${name}. Your appointment has been cancelled. Contact us at (608) 535-6057 to reschedule. - TotalGuard`,
  general: `Hi ${name}! Thanks for texting TotalGuard Yard Care. A team member will follow up shortly, or call (608) 535-6057 for immediate help.`
};

return [{ json: { reply: replies[intent] || replies.general, forward_to_owner: intent === 'general' || intent === 'quote_request', customer_id: customer?.id, intent } }];

const reply = $json.reply;
const from = $('Parse Inbound SMS').first().json.from;
const intent = $json.intent;
const forward_to_owner = $json.forward_to_owner;
const customer_id = $json.customer_id;

// Pass data to TG-94 for consent-checked, rate-limited SMS send
return [{ json: { to_phone: from, message_body: reply, workflow_name: 'TG-76', message_type: 'auto_reply', intent, forward_to_owner, customer_id } }];

const tg94Result = $input.first().json;
const payload = $('Prepare TG-94 Payload').first().json;
return [{ json: { ...payload, sms_sent: tg94Result.sent || false, sms_reason: tg94Result.reason || null, reply: payload.message_body } }];
